sum by (operation, status) (
  rate(
    hashi_sui_tx_submissions_total{
      alias="testnet",
    }[5m]
  )
)

sum by (operation, error_kind) (
  increase(
    hashi_leader_retries_total{
      alias="testnet",
    }[1h]
  )
)

sum by (status, path) (
  rate(
    hashi_requests{
      alias="testnet"
      }[5m]
  )
)

rate(
  hashi_request_latency_sum{
    alias="testnet",
    path!="unknown"
  }[5m]
)
/
rate(
  hashi_request_latency_count{
    alias="testnet",
    path!="unknown"
  }[5m]
)

